#include <bits/stdc++.h>using namespace std; using ll = long long; void solve() {    int n = 7;     vector<ll> a(n);    for(int i = 0; i < n; i++) {        cin >> a[i];    }             ll sum = 0;        for(int i = 0; i < n; i++) {        sum += a[i];    }            sum=2*max({a[0], a[1], a[2], a[3], a[4], a[5], a[6]})-sum;     cout << sum << "\n";} int main() {    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int t;    cin >> t;    while(t--) {        solve();    }    return 0;}